int dp[2][N];
void solve(int CASE)
{
	int n, m; cin >> n >> m;
	fa(i, 0, 1)fa(j, 1, 5e5)dp[i][j] = INF;
	var a = vector<int>(n + 1);
	var b = vector<int>(m + 1);
	int g = 0;
	fa(i, 1, n)cin >> a[i], g = Math::gcd(g, a[i]);
	fa(i, 1, m)cin >> b[i];

	// 类背包
	fa(i, 1, m) {
		fa(j, 1, 5e5)if (dp[(i - 1) % 2][j] != INF) {
			int g = Math::gcd(j, b[i]);
			dp[i % 2][g] = min(dp[i % 2][g], dp[(i - 1) % 2][j] + 1);
			dp[i % 2][j] = min(dp[i % 2][j], dp[(i - 1) % 2][j]);
		}
		dp[i % 2][b[i]] = 1;
		fa(j, 1, 5e5)dp[(i - 1) % 2][j] = INF;
	}

	// 能用的 dp 肯定很少
	var use = vector<pii>();
	fa(i, 1, 5e5)if (dp[m % 2][i] != INF)use.pb({ i, dp[m % 2][i] });

	int ans = INF;
	for (int p : Math::factorNumbers(g)) {
		int res = 0;
		bool ok = 1;
		fa(i, 1, n) {
			int now = INF;
			if (a[i] == p)now = 0;
			else {
				for (const var& [j, cnt] : use)
					if (Math::gcd(a[i], j) == p)
						now = min(now, cnt);
			}
			if (now == INF) {
				ok = 0;
				break;
			}
			res += now;
		}
		if (ok)ans = min(ans, res);
	}

	if (ans == INF)cout << -1 << endl;
	else cout << ans << endl;
	return;
}
